1. src/lib/invoice-list.ts 구현 (import 'server-only' 유지):
   pseudocode:
   async function listInvoices(): Promise<InvoiceSummary[]> {
     results = []
     cursor = undefined
     do {
       response = await notion.dataSources.query({ data_source_id: env.NOTION_DATABASE_ID, start_cursor: cursor })
       results.push(...response.results)
       cursor = response.has_more ? response.next_cursor : undefined
     } while (cursor)
     return results.map(mapPageToSummary)
   }
   function mapPageToSummary(page): InvoiceSummary {
     props = page.properties
     return {
       slug: page.id,
       invoiceNumber: readTitle(props['견적서 번호']) || readText(props['견적서 번호']) || '',
       clientName: readText(props['클라이언트명']) || '',
       issuedAt: readDate(props['발행일']) || '',
       status: readStatus(props['상태']) || '대기',
       total: readNumber(props['total']) || 0,
       isPublic: readStatus(props['상태']) === '승인'
     }
   }
