   pseudocode:
   function CopyLinkButton({ slug, isPublic }) {
     async function handleCopy() {
       url = (process.env.NEXT_PUBLIC_APP_URL || window.location.origin) + '/invoice/' + slug
       try {
         if (navigator.clipboard) await navigator.clipboard.writeText(url)
         else fallbackCopy(url)  // textarea 방식
         toast.success('링크가 복사되었습니다.')
       } catch { toast.error('복사에 실패했습니다.') }
     }
     return <Button disabled={!isPublic} onClick={handleCopy} title={!isPublic ? '승인된 견적서만 공유 가능' : ''}>링크 복사</Button>
   }
